sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	// Add your code here
	var combatants = new GlideRecord('x_176383_star_wars_combatant');
	combatants.addActiveQuery().addCondition('combat_tracker', current.combat_tracker).addCondition('status', 'NOT IN', 'going,gone');
	combatants.orderBy('order');
	combatants.setLimit(1);
	combatants.query();
	if(combatants.next()){
		combatants.status = 'going';
		combatants.update();
	} else{
		combatants = new GlideRecord('x_176383_star_wars_combatant');
		combatants.addActiveQuery().addCondition('combat_tracker', current.combat_tracker);
		combatants.orderBy('order');
		combatants.query();
		var index = 0;
		while(combatants.next()){
			if(index == 0){
				combatants.status = 'going';
			} else{
				combatants.status = 'pending';
			}
			combatants.update();
			index++;
		}

		var combatTracker = new GlideRecord('x_176383_star_wars_combat_tracker');
		combatTracker.get(current.combat_tracker.sys_id);
		combatTracker.round = parseInt(combatTracker.round) + 1;
		combatTracker.update();
	}
})(current, previous);
